style.css:
* {
        margin: 0;
        padding: 0;
        box-sizing: border-box;
      }

      body {
        min-height: 100vh;
        display: flex;
        align-items: center;
        justify-content: center;
        background-color: #fafbfc;
        background-image:
          linear-gradient(rgba(0, 0, 0, 0.04) 1px, transparent 1px),
          linear-gradient(90deg, rgba(0, 0, 0, 0.04) 1px, transparent 1px);
        background-size: 32px 32px;
        font-family:
          -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
        padding: 40px;
      }

      .book-list-container {
        position: relative;
        max-width: 500px;
        width: 100%;
      }

      .book-list {
        list-style: none;
        background: rgba(255, 255, 255, 0.6);
        border-radius: 12px;
        padding: 8px;
        backdrop-filter: blur(10px);
      }

      .book-item {
        position: relative;
      }

      .book-link {
        display: flex;
        align-items: center;
        padding: 16px 20px;
        color: #2d3748;
        text-decoration: none;
        font-size: 15px;
        font-weight: 500;
        border-radius: 8px;
        transition:
          background-color 0.2s ease,
          transform 0.2s ease;
        position: relative;
      }

      .book-link::before {
        content: attr(data-number);
        color: #a0aec0;
        font-size: 13px;
        margin-right: 16px;
        min-width: 24px;
        font-weight: 400;
      }

      .book-link:hover {
        background-color: rgba(255, 255, 255, 0.9);
        transform: translateX(4px);
      }

      /* Tooltip positioned outside list item, appearing from left */
      .book-preview {
        position: absolute;
        left: -100px; /* Outside the list container */
        top: 50%;
        transform: translateY(-50%) scale(0.9);
        width: 80px;
        height: 110px;
        border-radius: 6px;
        object-fit: cover;
        box-shadow: 0 8px 24px rgba(0, 0, 0, 0.2);
        opacity: 0;
        pointer-events: none;
        transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
        z-index: 100;
      }

      .book-link:hover .book-preview {
        opacity: 1;
        transform: translateY(-50%) scale(1);
        left: -90px; /* Slight movement on appear */
      }

      .book-meta {
        margin-left: auto;
        color: #a0aec0;
        font-size: 13px;
        font-weight: 400;
      }
